'use client';

import Image from 'next/image';

type Props = {
  name: string;
  icon: string;
};

export default function SkillGlassCard({ name, icon }: Props) {
  return (
    <div className='relative w-full h-35 group'>
      <div
        className='
          relative z-10
          w-full h-full
          rounded-2xl
          bg-white/1
          backdrop-blur-sm
          border border-white/20
          shadow-[0_8px_32px_rgba(0,0,0,0.1)]
          p-5
          gap-1
          flex
          flex-col
          justify-between
          align-center
          transition
          duration-300
          group-hover:scale-[1.02]
        '
      >
        <Image
          src={icon}
          alt=''
          width={100}
          height={100}
          className='opacity-50 blur-sm absolute grayscale -z-10 w-20 h-20 top-1/2 left-1/4 transform translate-x-1/16 -translate-y-1/2'
        />
        <Image
          src={icon}
          alt=''
          width={100}
          height={100}
          className='w-20 h-20'
        />

        <h3 className='text-lg text-center font-semibold text-black/70'>
          {name}
        </h3>
      </div>
    </div>
  );
}
