'use client';

import { useEffect, useRef, useState, useCallback } from 'react';
import {
  AnimatePresence,
  motion,
  useMotionValue,
  useSpring,
} from 'framer-motion';

import Hero from '@/components/Hero';
import About from '@/components/About';
import Skills from '@/components/Skills';
import Section from '@/components/Section';
import Navbar from '@/components/Navbar';
import DotNavigation from '@/components/DotNavigation';

export default function Home() {
  const sections = [
    { id: 'home', Component: Hero },
    { id: 'about', Component: About },
    { id: 'skills', Component: Skills },
    { id: 'projects', Component: Hero },
    { id: 'experience', Component: Hero },
    { id: 'contact', Component: Hero },
  ];

  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);

  const smoothX = useSpring(mouseX, { stiffness: 120, damping: 20 });
  const smoothY = useSpring(mouseY, { stiffness: 120, damping: 20 });

  const [activeIndex, setActiveIndex] = useState(0);
  const isAnimating = useRef(false);

  // 🔥 Smooth scroll (wheel)
  const goToSmooth = useCallback(
    (index: number) => {
      if (index === activeIndex) return;

      isAnimating.current = true;
      setActiveIndex(index);

      setTimeout(() => {
        isAnimating.current = false;
      }, 600);
    },
    [activeIndex],
  );

  // 🔥 Instant jump (click)
  const goToInstant = useCallback((index: number) => {
    setActiveIndex(index);
  }, []);

  // 🔥 Wheel control
  useEffect(() => {
    const handleWheel = (e: WheelEvent) => {
      if (isAnimating.current) return;

      if (e.deltaY > 0 && activeIndex < sections.length - 1) {
        goToSmooth(activeIndex + 1);
      } else if (e.deltaY < 0 && activeIndex > 0) {
        goToSmooth(activeIndex - 1);
      }
    };

    window.addEventListener('wheel', handleWheel, { passive: true });
    return () => window.removeEventListener('wheel', handleWheel);
  }, [activeIndex, goToSmooth, sections.length]);

  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === 'ArrowDown') goToSmooth(activeIndex + 1);
      if (e.key === 'ArrowUp') goToSmooth(activeIndex - 1);
    };

    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [activeIndex, goToSmooth]);

  const touchStartY = useRef(0);

  useEffect(() => {
    const handleTouchStart = (e: TouchEvent) => {
      touchStartY.current = e.touches[0].clientY;
    };

    const handleTouchEnd = (e: TouchEvent) => {
      const delta = touchStartY.current - e.changedTouches[0].clientY;

      if (Math.abs(delta) < 50) return;

      if (delta > 0 && activeIndex < sections.length - 1) {
        goToSmooth(activeIndex + 1);
      } else if (delta < 0 && activeIndex > 0) {
        goToSmooth(activeIndex - 1);
      }
    };

    window.addEventListener('touchstart', handleTouchStart);
    window.addEventListener('touchend', handleTouchEnd);

    return () => {
      window.removeEventListener('touchstart', handleTouchStart);
      window.removeEventListener('touchend', handleTouchEnd);
    };
  }, [activeIndex, goToSmooth, sections.length]);

  const backgrounds = [
    'bg-white',
    'bg-blue-50',
    'bg-purple-50',
    'bg-green-50',
    'bg-yellow-50',
    'bg-pink-50',
  ];

  return (
    <>
      <motion.div
        className='fixed top-0 left-0 h-0.75 bg-black z-50'
        animate={{
          width: `${((activeIndex + 1) / sections.length) * 100}%`,
        }}
        transition={{ duration: 0.4 }}
      />
      <motion.div
        className='fixed inset-0 -z-10'
        animate={{
          backgroundColor: backgrounds[activeIndex],
        }}
        transition={{ duration: 0.6 }}
      />
      <div
        className='fixed inset-0'
        onMouseMove={(e) => {
          mouseX.set(e.clientX);
          mouseY.set(e.clientY);
        }}
      />
      <motion.div
        className='pointer-events-none fixed inset-0 z-10'
        style={{
          background: smoothX.to(
            (x) =>
              `radial-gradient(600px at ${x}px ${smoothY.get()}px, rgba(255,255,255,0.15), transparent 70%)`,
          ),
        }}
      />
      {/* 🔥 NAVBAR */}
      <Navbar
        active={sections[activeIndex].id}
        onNavigate={(id: string) => {
          const index = sections.findIndex((s) => s.id === id);
          if (index !== -1) goToInstant(index);
        }}
      />

      {/* 🔥 DOT NAV */}
      <DotNavigation
        active={sections[activeIndex].id}
        onClick={(id: string) => {
          const index = sections.findIndex((s) => s.id === id);
          if (index !== -1) goToInstant(index);
        }}
      />

      {/* 🔥 MAIN VIEW */}
      <div className='fixed inset-0 overflow-hidden'>
        <div className='absolute inset-0 -z-10 blur-3xl bg-black/5 rounded-full' />

        <AnimatePresence mode='wait'>
          <Section key={sections[activeIndex].id}>
            {(() => {
              const ActiveComponent = sections[activeIndex].Component;
              return <ActiveComponent />;
            })()}
          </Section>
        </AnimatePresence>
      </div>
    </>
  );
}
